`ATriggerBox` türetip constructor içinde `OnActorBeginOverlap` event'ine fonksiyon bağlayabilirsin.

```cpp
// MyTriggerBox.h
#pragma once

#include "CoreMinimal.h"
#include "Engine/TriggerBox.h"
#include "MyTriggerBox.generated.h"

UCLASS()
class AMyTriggerBox : public ATriggerBox
{
    GENERATED_BODY()

public:
    AMyTriggerBox();

protected:
    UFUNCTION()
    void BeginOverlap(AActor* OverlappedActor, AActor* OtherActor);
};
```

```cpp
// MyTriggerBox.cpp
#include "MyTriggerBox.h"
#include "Engine/Engine.h"

AMyTriggerBox::AMyTriggerBox()
{
    OnActorBeginOverlap.AddDynamic(this, &AMyTriggerBox::BeginOverlap);
}

void AMyTriggerBox::BeginOverlap(AActor* OverlappedActor, AActor* OtherActor)
{
    if (GEngine)
    {
        GEngine->AddOnScreenDebugMessage(-1, 5.0f, FColor::Green, TEXT("Begin Overlap"));
    }
}
```

Health'i ayrı component yapmak Player, enemy ve kırılabilir objelerde yeniden kullanımı kolaylaştırır.

```csharp
using System;
using UnityEngine;

public class Health : MonoBehaviour
{
    [SerializeField] private int maxHealth = 100;

    public int Current { get; private set; }
    public event Action<int, int> Changed;
    public event Action Died;

    private void Awake()
    {
        Current = maxHealth;
    }

    public void TakeDamage(int amount)
    {
        Current = Mathf.Max(Current - amount, 0);
        Changed?.Invoke(Current, maxHealth);

        if (Current == 0)
            Died?.Invoke();
    }
}
```

